define("quiz_paperentry/edit_answer",[],(function(){"use strict";return{init:function(qdata,current,noattemptmsg,curlabelmsg){var studentSel=document.getElementById("ea-student-select"),questionSel=document.getElementById("ea-question-select"),answersArea=document.getElementById("ea-answers-area"),submitBtn=document.getElementById("ea-submit-btn"),hiddenUser=document.getElementById("ea-userid-hidden"),hiddenSlot=document.getElementById("ea-slot-hidden"),hiddenIndex=document.getElementById("ea-index-hidden");if(!studentSel)return;function updateAnswers(){var uid=studentSel.value,slot=questionSel.value;answersArea.innerHTML="";hiddenUser.value=uid;hiddenSlot.value=slot;hiddenIndex.value="";submitBtn.disabled=true;if(!uid||!slot)return;var q=qdata[slot];if(!q)return;if(!(uid in current)){var p=document.createElement("p");p.className="text-muted font-italic";p.textContent=noattemptmsg;answersArea.appendChild(p);return}var userSlots=current[uid]||{},currentIdx=slot in userSlots?userSlots[slot]:null;q.answers.forEach((function(text,idx){var isCurrent=null!==currentIdx&&currentIdx===idx,div=document.createElement("div");div.className="form-check";var radio=document.createElement("input");radio.type="radio";radio.name="ea_answer_ui";radio.className="form-check-input";radio.id="ea-ans-"+idx;radio.value=idx;radio.addEventListener("change",(function(){hiddenIndex.value=idx;submitBtn.disabled=false}));var lbl=document.createElement("label");lbl.className="form-check-label";lbl.htmlFor="ea-ans-"+idx;lbl.appendChild(document.createTextNode(String.fromCharCode(65+idx)+". "+text));if(isCurrent){var note=document.createElement("small");note.style.cssText="background:#f0f0f0;border-radius:3px;padding:1px 5px;margin-left:6px;color:#888";note.textContent=curlabelmsg;lbl.appendChild(note)}div.appendChild(radio);div.appendChild(lbl);answersArea.appendChild(div)}))}studentSel.addEventListener("change",updateAnswers);questionSel.addEventListener("change",updateAnswers)}};}));
